1	export type Item = { type: string };
2	
3	export type QuoteStep = { op: "quote"; items: Item[] };
4	
5	export type Step = QuoteStep;
6	
7	export type Scenario = {
8	  customer: { yearsWithMHPCO: number };
9	  steps: Step[];
10	};
11	
12	export type QuoteResult = { premium: number };
13	
14	export type ScenarioResult = {
15	  results: QuoteResult[];
16	};
17	
18	const PROCESSING_FEE = 5;
19	
20	const BASE_PREMIUMS: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	};
27	
28	const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
29	
30	const sumBasePremiums = (items: Item[]): number =>
31	  items.reduce((sum, item) => sum + basePremium(item), 0);
32	
33	const quote = (step: QuoteStep): QuoteResult => ({
34	  premium: sumBasePremiums(step.items) + PROCESSING_FEE,
35	});
36	
37	export const runScenario = (scenario: Scenario): ScenarioResult => ({
38	  results: scenario.steps.map(quote),
39	});
40

1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Edge case: empty quote ---
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Single-item base premiums + processing fee ---
15	  it("quote with a single plain sword → premium 105 G (100 base + 5 fee)", () => {
16	    const result = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result).toEqual({ results: [{ premium: 105 }] });
21	  });
22	  it("quote with a single plain amulet → premium 65 G (60 base + 5 fee)", () => {
23	    const result = runScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 65 }] });
28	  });
29	  it("quote with a single plain staff → premium 85 G (80 base + 5 fee)", () => {
30	    const result = runScenario({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
33	    });
34	    expect(result).toEqual({ results: [{ premium: 85 }] });
35	  });
36	  it("quote with a single plain potion → premium 45 G (40 base + 5 fee)", () => {
37	    const result = runScenario({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
40	    });
41	    expect(result).toEqual({ results: [{ premium: 45 }] });
42	  });
43	
44	  // --- Components ---
45	  it("quote with a single rune → premium 30 G (25 base + 5 fee)", () => {
46	    const result = runScenario({
47	      customer: { yearsWithMHPCO: 0 },
48	      steps: [{ op: "quote", items: [{ type: "rune" }] }],
49	    });
50	    expect(result).toEqual({ results: [{ premium: 30 }] });
51	  });
52	  it("quote with 2 runes → 50 G base + 5 fee = 55 G", () => {
53	    const result = runScenario({
54	      customer: { yearsWithMHPCO: 0 },
55	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
56	    });
57	    expect(result).toEqual({ results: [{ premium: 55 }] });
58	  });
59	  it.todo("quote with 3 runes (block) → 60 G base + 5 fee = 65 G");
60	  it.todo("quote with 4 runes → 100 G base + 5 fee = 105 G (no block — block requires exactly 3)");
61	  it.todo("quote with 7 runes → 175 G base + 5 fee = 180 G");
62	
63	  // --- 'Alike' clarification ---
64	  it.todo("quote with 2 runes + 1 moonstone → 75 G base + 5 fee = 80 G (no block — different types)");
65	  it.todo("quote with 3 runes + 3 moonstones → 120 G base + 5 fee = 125 G (two separate blocks)");
66	
67	  // --- Item-specific modifiers in isolation ---
68	  it.todo("cursed sword (no other modifiers) → 100 base + 50 curse + 5 fee = 155 G");
69	  it.todo("sword with enchantment 5 → 100 base + 30 high-enchantment + 5 fee = 135 G");
70	  it.todo("sword with enchantment 4 → no high-enchantment surcharge → 105 G");
71	  it.todo("cursed sword with enchantment 5 → both surcharges → 100 + 50 + 30 + 5 = 185 G");
72	
73	  // --- Policy-wide modifiers in isolation ---
74	  it.todo("loyalty discount: 2-year customer, plain sword → 100 − 20 + 5 = 85 G");
75	  it.todo("first insurance surcharge: 0-year, plain sword (first quote) → 100 + 10 + 5 = 115 G");
76	  it.todo("follow-up contract discount: second quote in scenario, plain sword (0-year) → 100 + 10 − 15 + 5 = 100 G");
77	
78	  // --- Modifier scope on multi-item policies ---
79	  it.todo("cursed sword + plain amulet → policy 160 G base + 50 curse = 210 + 5 fee = 215 G");
80	
81	  // --- Rounding ---
82	  it.todo("premium calculation yielding 197.5 G → final 198 G (rounded up in MHPCO's favor)");
83	
84	  // --- Integration examples ---
85	  it.todo("newcomer with cursed sword (0 yrs, enchantment 3) → 165 G");
86	  it.todo("long-standing customer's second quote: cursed sword enchantment 7 (3 yrs) → 160 G");
87	
88	  // --- Error handling for quote ---
89	  it.todo("quote with unknown item type (e.g. broomstick) → throws error");
90	
91	  // --- Claim: standard reimbursement ---
92	  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G");
93	  it.todo("rune damaged 200 G → payout 100 G (no special clauses; deductible applies)");
94	
95	  // --- Claim: deductible per damage event ---
96	  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → payout 600 G (deductible applied per item)");
97	
98	  // --- Claim: special clauses ---
99	  it.todo("dragon-material sword enchantment 8, damage 1000 G → payout 400 G (50% then deductible)");
100	  it.todo("dragon-material sword enchantment 9, damage 1000 G → payout 400 G (50% rule wins, then deductible)");
101	  it.todo("dragon-material sword enchantment 5, damage 800 G → payout 700 G (full dragon reimbursement minus deductible)");
102	  it.todo("steel sword enchantment 9, damage 1000 G → payout 400 G (high-enchantment 50% then deductible)");
103	
104	  // --- Claim: cap ---
105	  it.todo("policy with sword and amulet → insurance sum 1600 G, cap 3200 G");
106	  it.todo("cursed sword (insurance value 1000 G, modified premium 165 G) → cap 2000 G (premium modifiers don't raise cap)");
107	  it.todo("policy with sword and 3 runes (block) → insurance sum 1750 G (block discount doesn't affect insurance sum)");
108	
109	  // --- Cap exhaustion across successive claims ---
110	  it.todo("sword (cap 2000 G), two successive claims of 1500 G each → 1st payout 1400, remaining 600; 2nd payout 600, remaining 0");
111	
112	  // --- Multiple items of same type ---
113	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
114	  it.todo("dragon attack damages both swords (two sword damages) → each treated as separate damage with its own deductible");
115	
116	  // --- Claim error handling ---
117	  it.todo("damages contains more entries of a type than insured → claim rejected (error)");
118	  it.todo("claim references item not in policy → error");
119	  it.todo("claim damage entry with negative amount → error");
120	
121	  // --- Payout rounding ---
122	  it.todo("payout calculation yielding 350.5 G → final 350 G (rounded down in MHPCO's favor)");
123	});
